{
var seed = GetInt(parameters, "seed", context.Seed);
var shape = GetChoice(parameters, "shape", "circle");
var size = GetFloat(parameters, "size", 0.5f);
var density = GetFloat(parameters, "density", 0.6f);
var blobCount = Math.Max(2, GetInt(parameters, "blobCount", 5));
var leafColor = GetColor(parameters, "leafColor", Color.FromRgb(80, 160, 60));
var shadowColor = GetColor(parameters, "shadowColor", Color.FromRgb(40, 90, 30));
var highlightColor = GetColor(parameters, "highlightColor", Color.FromRgb(130, 220, 100));
var brightness = GetFloat(parameters, "brightness", 0f);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var lR = leafColor.R / 255f; var lG = leafColor.G / 255f; var lB = leafColor.B / 255f;
var sR = shadowColor.R / 255f; var sG = shadowColor.G / 255f; var sB = shadowColor.B / 255f;
var hR = highlightColor.R / 255f; var hG = highlightColor.G / 255f; var hB = highlightColor.B / 255f;

var halfSize = tileSize * 0.5f;
var bushRadius = halfSize * size;

// Generate blob positions and radii deterministically
var blobData = new (float cx, float cy, float radius)[blobCount];
for (var i = 0; i < blobCount; i++)
{
    var angle = (i / (float)blobCount) * MathF.Tau + HashToUnit(i, 0, seed) * 0.5f;
    var distFactor = shape switch
    {
        "ellipse" => 0.6f + HashToUnit(i, 1, seed) * 0.3f,
        "irregular" => 0.3f + HashToUnit(i, 2, seed) * 0.6f,
        _ => 0.4f + HashToUnit(i, 3, seed) * 0.3f
    };
    var bx = MathF.Cos(angle) * bushRadius * distFactor;
    var by = MathF.Sin(angle) * bushRadius * distFactor * (shape == "ellipse" ? 0.7f : 1f);
    var br = bushRadius * (0.3f + HashToUnit(i, 4, seed) * 0.4f) * density;
    blobData[i] = (bx, by, br);
}

buffer.ParallelForEachPixel((x, y) =>
{
    var px = x + 0.5f - halfSize;
    var py = y + 0.5f - halfSize;

    // Compute distance to each blob
    var maxContrib = 0f;
    var nearestBlob = 0;
    for (var i = 0; i < blobCount; i++)
    {
        var (bx, by, br) = blobData[i];
        var dx = px - bx;
        var dy = py - by;
        var dist = MathF.Sqrt(dx * dx + dy * dy);

        if (br <= 0.001f) continue;

        // Soft falloff from blob center
        var contrib = 1f - dist / br;
        contrib = Math.Clamp(contrib, 0f, 1f);
        contrib = contrib * contrib * (3f - 2f * contrib); // smoothstep

        if (contrib > maxContrib)
        {
            maxContrib = contrib;
            nearestBlob = i;
        }
    }

    if (maxContrib <= 0.01f)
    {
        buffer.SetPixel(x, y, 0, 0, 0, 0);
        return;
    }

    // Per-blob color variation
    var blobHash = HashToUnit(nearestBlob, 0, seed + 200);
    var variation = (blobHash - 0.5f) * 0.15f;

    // Lighting: top-left directional
    var light = (1f - px / halfSize) * 0.3f + (1f - py / halfSize) * 0.3f;
    light = Math.Clamp(light * maxContrib + 0.2f, 0f, 1f);

    // Blend leaf color with shadow/highlight based on light
    float finalR, finalG, finalB;
    if (light < 0.5f)
    {
        var lt = light * 2f;
        finalR = Lerp(sR, lR, lt) + variation;
        finalG = Lerp(sG, lG, lt) + variation;
        finalB = Lerp(sB, lB, lt) + variation;
    }
    else
    {
        var lt = (light - 0.5f) * 2f;
        finalR = Lerp(lR, hR, lt) + variation;
        finalG = Lerp(lG, hG, lt) + variation;
        finalB = Lerp(lB, hB, lt) + variation;
    }

    // Brightness
    if (MathF.Abs(brightness) > 0.001f)
    {
        finalR += brightness;
        finalG += brightness;
        finalB += brightness;
    }

    // Internal edge: slightly darker at blob boundaries for depth
    var internalEdge = Math.Abs(maxContrib - 0.5f) * 2f;
    var darkening = 1f - (1f - internalEdge) * 0.15f;
    finalR *= darkening;
    finalG *= darkening;
    finalB *= darkening;

    buffer.SetPixel(x, y,
        Math.Clamp(finalR, 0f, 1f),
        Math.Clamp(finalG, 0f, 1f),
        Math.Clamp(finalB, 0f, 1f),
        Math.Clamp(maxContrib, 0f, 1f));
});

return buffer;
}
